nged title based on wikidata|lt=2247 AD|qq=|ja_comment=jawiki redirects to 23世紀|1=23rd century|WD=Q49832}} * {{ill|2307 AD|ja|2307年|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2307|comment=changed title based on wikidata|lt=2307 AD|qq=|ja_comment=jawiki redirects to 24世紀|1=24th century|WD=Q49838}} * {{ill|2367 AD|ja|2367年|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2367|comment=changed title based on wikidata|lt=2367 AD|qq=|ja_comment=jawiki redirects to 24世紀|1=24th century|WD=Q49838}} * {{ill|2427 AD|ja|2427年|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2427|comment=likely broken Sexagenary year|lt=2427 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2487 AD|ja|2487年|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2487|comment=likely broken Sexagenary year|lt=2487 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2547 AD|ja|2547年|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2547|comment=likely broken Sexagenary year|lt=2547 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2607 AD|ja|2607年|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2607|comment=likely broken Sexagenary year|lt=2607 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2667 AD|ja|2667年|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2667|comment=likely broken Sexagenary year|lt=2667 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2727 AD|ja|2727年|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2727|comment=likely broken Sexagenary year|lt=2727 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2787 AD|ja|2787年|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2787|comment=likely broken Sexagenary year|lt=2787 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2847 AD|ja|2847年|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2847|comment=likely broken Sexagenary year|lt=2847 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2907 AD|ja|2907年|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2907|comment=likely broken Sexagenary year|lt=2907 AD|qq=|ja_comment=jawiki link in